<template><ion-page><AppHeader /><ion-content class="vivid-page"><div class="page-shell"><div class="title-row"><div><h1>Fornecedores</h1><p>Gerencie sua rede de parceiros.</p></div><button class="icon-button" @click="store.fetch"><ion-icon :icon="refreshOutline" /></button></div><AppField v-model="query" placeholder="Buscar por nome ou CNPJ..." :icon="searchOutline" /><AppState v-if="store.loading" loading title="Carregando fornecedores" /><AppState v-else-if="!filtered.length" title="Nenhum fornecedor encontrado" /><div v-else class="supplier-list"><article v-for="supplier in filtered" :key="supplier.id" class="supplier-card vivid-card"><div class="supplier-icon"><ion-icon :icon="businessOutline" /></div><div><h3>{{ supplier.name }}</h3><p class="tech-label">{{ supplier.taxId || 'Documento não informado' }}</p><p>{{ supplier.contactInfo || 'Contato não informado' }}</p></div><div class="actions"><button @click="$router.push(`/suppliers/${supplier.id}/edit`)"><ion-icon :icon="createOutline" /></button><button @click="remove(supplier.id)"><ion-icon :icon="trashOutline" /></button></div></article></div><button class="fab" @click="$router.push('/suppliers/new')">+</button></div><BottomNav /></ion-content></ion-page></template>
<script setup lang="ts">import { computed,ref } from 'vue'; import { IonPage,IonContent,IonIcon,alertController,onIonViewWillEnter } from '@ionic/vue'; import { refreshOutline,searchOutline,businessOutline,createOutline,trashOutline } from 'ionicons/icons'; import AppHeader from '@/components/AppHeader.vue';import BottomNav from '@/components/BottomNav.vue';import AppField from '@/components/AppField.vue';import AppState from '@/components/AppState.vue';import { useSuppliersStore } from '@/stores/suppliers';const store=useSuppliersStore(),query=ref('');const filtered=computed(()=>store.items.filter(s=>`${s.name} ${s.taxId||''}`.toLowerCase().includes(query.value.toLowerCase())));const remove=async(id:string)=>{const a=await alertController.create({header:'Excluir fornecedor?',message:'Esta ação não pode ser desfeita.',buttons:[{text:'Cancelar',role:'cancel'},{text:'Excluir',role:'destructive',handler:()=>store.remove(id)}]});a.present()};onIonViewWillEnter(()=>store.fetch());</script>
<style scoped>.title-row{display:flex;justify-content:space-between;align-items:center;padding:22px 0 12px}.title-row h1{margin:0}.title-row p{color:var(--vivid-muted)}.supplier-list{display:grid;gap:14px}.supplier-card{display:grid;grid-template-columns:48px 1fr auto;gap:12px;padding:16px}.supplier-card h3,.supplier-card p{margin:0 0 6px}.supplier-card p{color:var(--vivid-muted);font-size:12px}.supplier-icon{width:46px;height:46px;border-radius:12px;background:#34293a;display:grid;place-items:center;color:var(--vivid-primary-bright);font-size:24px}.actions{display:flex;gap:4px}.actions button{border:0;background:transparent;color:var(--vivid-primary-bright);font-size:20px}.fab{position:fixed;right:22px;bottom:94px;width:58px;height:58px;border:0;border-radius:16px;background:var(--vivid-primary);font-size:32px;color:#16001e}</style>
